    """Detect whether an STL file is binary format."""
    import os
    size = os.path.getsize(path)
    with open(path, 'rb') as fh:
        header = fh.read(80)
        if len(header) < 80:
            return False
        count_bytes = fh.read(4)
        if len(count_bytes) < 4:
            return False
        num_triangles = struct.unpack('<I', count_bytes)[0]
    # Binary STL size: 80 (header) + 4 (count) + num_triangles * 50
