    if size == expected_size and expected_size > 84:
        # Try to disambiguate: if it starts with 'solid' but size matches binary
        # Check if lines 2+ look like ASCII STL
        with open(path, 'r', errors='replace') as fh:
            lines = fh.readlines()
        has_facet = any('facet normal' in l for l in lines[:10])
        if not has_facet:
            return True
    return False


