    """Parse and validate an STL file (ASCII or binary)."""
    issues = []

    # Detect format
    try:
        is_binary = _is_binary_stl(path)
    except Exception as e:
        return {"valid": False, "triangle_count": 0, "surface_area": 0,
                "issues": [f"Could not read file: {e}"]}

    if is_binary:
        result = parse_binary_stl(path)
        triangles, parse_issues = result
    else:
        triangles, parse_issues = parse_ascii_stl(path)

    issues.extend(parse_issues)

